    for i in range(len(targetWords)):
        for j in range(len(startWords[i])):
            if self.canConvert(startWords[i], targetWords[i][j]:
                count += 1
    return count

def canConvert(self, startWord, targetWord):
    if len(startWord) != len(targetWord):
        return False
    for i in range(len(targetWord)):
        if targetWord[i] not in startWord:
            return False
